605→export const getForYouFeedService = async (limit, userId, offset) => {
606→    if (!userId) {
607→        throw { status: 401, error: 'authentication required' };
608→    }
609→    if (isNaN(limit) || limit > 20 || limit < 1) {
610→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
611→    }
612→
613→    const parsedLimit = parseInt(limit);
614→    const parsedOffset = parseInt(offset) || 0;
615→
616→    const { data: rpcData, error } = await supabase.rpc('get_for_you_feed', {
617→        p_user_id: userId,
618→        p_limit: parsedLimit + 1,
619→        p_offset: parsedOffset
620→    });
621→
622→    if (error) {
