646→        users: { id: row.user_obj_id, name: row.user_name, image_url: row.user_image_url, badge: row.user_badge },
647→        like_count: [{ count: Number(row.like_count) }],
648→        reaction_count: [{ count: Number(row.reaction_count) }],
649→        comment_count: [{ count: Number(row.comment_count) }],
650→        bookmark_count: [{ count: Number(row.bookmark_count) }]
651→    }));
652→
653→    // Personalization (same pattern as getFollowingFeedService)
654→    const journalIds = data.map(j => j.id);
655→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
656→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
657→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
658→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
659→    ]);
660→
661→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
662→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
663→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
664→
665→    await attachRepostSources(data);
666→
667→    const formattedData = data.map(journal => ({
668→        ...journal,
669→        has_liked: userHasLikedSet.has(journal.id),
670→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
671→        user_reaction: userReactionMap.get(journal.id) || null
672→    }));
673→
674→    const hasMore = data.length > parsedLimit;
675→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
676→
677→    return { data: slicedData, hasMore };
678→}
