680→export const getMonthlyHottestJournalsService = async(limit, userId) => {
681→    if(isNaN(limit) || limit < 1 || limit > 10){
682→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
683→    }
684→
685→    const parsedLimit = parseInt(limit);
686→    const now = new Date();
687→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
688→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
689→
690→    // Use server-side RPC to score and sort — avoids fetching ALL monthly posts
691→    const {data: rpcData, error: rpcError} = await supabase.rpc('get_monthly_hottest_journals', {
692→        p_limit: parsedLimit
693→    });
694→
695→    if(rpcError){
696→        console.error('supabase RPC error (get_monthly_hottest_journals):', rpcError.message);
697→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
698→    }
699→
700→    // Reshape RPC rows to match the format the client expects
701→    const journals = (rpcData || []).map((row) => ({
702→        id: row.id,
703→        user_id: row.user_id,
704→        title: row.title,
705→        preview_text: row.preview_text || '',
706→        thumbnail_url: row.thumbnail_url || null,
707→        post_type: row.post_type,
708→        created_at: row.created_at,
709→        privacy: row.privacy,
710→        views: row.views,
711→        is_repost: row.is_repost,
712→        repost_source_journal_id: row.repost_source_journal_id,
713→        repost_caption: row.repost_caption,
714→        users: {
715→            id: row.user_id,
716→            name: row.user_name,
717→            image_url: row.user_image_url,
718→            badge: row.user_badge
719→        },
720→        like_count: [{count: row.like_count}],
721→        comment_count: [{count: row.comment_count}],
722→        bookmark_count: [{count: row.bookmark_count}],
723→        hot_score: row.hot_score
724→    }));
725→
726→    const journalsWithInteractions = await attachUserInteractionFlags(journals, userId);
727→
728→    return {
729→        data: journalsWithInteractions,
730→        period: {
731→            startUtc: monthStartUtc.toISOString(),
732→            endUtc: nextMonthStartUtc.toISOString(),
733→            timezone: 'UTC'
734→        },
735→        totalCandidates: journalsWithInteractions.length
736→    };
737→}
